			newAssignCandidate = dispatch.AssignsLen
		}
		evaluateOnAssign := func(idx int) bool {
			var ok bool
			if idx == newAssignCandidate {
				ok = true
				assignPtr := &dispatch.Assigns[idx]
				assignPtr.Cost = 0.0
				assignPtr.AddShip(total_ship+shipIdx, oris[shipIdx], dess[shipIdx])
