For each order, evaluate insertion into all existing assigns using a cost-delta metric, select the minimum positive delta, and create a new assign as fallback.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	orderCount := len(oris)
	assignCount := dispatch.AssignsLen

	for orderIdx := 0; orderIdx < orderCount; orderIdx++ {
		shipID := total_ship + orderIdx
		bestAssignIdx := -1
		minDelta := math.Inf(1)

		for i := 0; i < assignCount; i++ {
			savedState := dispatch.Assigns[i]
			if dispatch.Assigns[i].AddShip(shipID, oris[orderIdx], dess[orderIdx]) {
				oldCost := savedState.Cost
				dispatch.Assigns[i].GenRoute()
				newCost := dispatch.Assigns[i].Cost
				if newCost >= 0 {
					delta := newCost - oldCost
					if delta < minDelta {
						minDelta = delta
						bestAssignIdx = i
					}
				}
			}
			dispatch.Assigns[i] = savedState
			dispatch.Assigns[i].GenRoute()
		}

		fallbackNeeded := true
		if bestAssignIdx != -1 && minDelta < math.Inf(1) {
			if dispatch.Assigns[bestAssignIdx].AddShip(shipID, oris[orderIdx], dess[orderIdx]) {
				dispatch.Assigns[bestAssignIdx].GenRoute()
				fallbackNeeded = false
			}
		}

		if fallbackNeeded {
			newIdx := dispatch.AssignsLen
			if newIdx >= MAXASSIGNS {
				newIdx = assignCount
			}
			ok := dispatch.Assigns[newIdx].AddShip(shipID, oris[orderIdx], dess[orderIdx])
			if ok {
				dispatch.Assigns[newIdx].GenRoute()
				if newIdx == dispatch.AssignsLen && newIdx < MAXASSIGNS {
					dispatch.AssignsLen++
				}
			} else {
				for k := 0; k < assignCount; k++ {
					dispatch.Assigns[k].AddShip(shipID, oris[orderIdx], dess[orderIdx])
					dispatch.Assigns[k].GenRoute()
					if dispatch.Assigns[k].Cost >= 0 {
						fallbackNeeded = false
						break
					}
					dispatch.Assigns[k].RemoveShip(shipID)
					dispatch.Assigns[k].GenRoute()
				}
				if fallbackNeeded && newIdx < MAXASSIGNS {
					dispatch.Assigns[newIdx].AddShip(shipID, oris[orderIdx], dess[orderIdx])
					dispatch.Assigns[newIdx].GenRoute()
					if newIdx == dispatch.AssignsLen {
						dispatch.AssignsLen++
					}
				}
			}
		}
	}

	dispatch.RenewnTotalCost()
	return dispatch

