func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type candidate struct {
		assignIdx int
		costDelta float64
		feasible   bool
	}

	// Process each ship order sequentially
	for shipIDOffset := range oris {
		ori := oris[shipIDOffset]
		des := dess[shipIDOffset]
		shipID := total_ship + shipIDOffset

		bestCandidate := candidate{-1, 0.0, false}

		// Try inserting into existing non-empty assigns first (shuffled)
		existingIndices := make([]int, 0, dispatch.AssignsLen)
		for i := 0; i < dispatch.AssignsLen; i++ {
			if dispatch.Assigns[i].StationsLen > 0 {
				existingIndices = append(existingIndices, i)
			}
		}
		// Shuffle to avoid bias
		for i := len(existingIndices) - 1; i > 0; i-- {
			j := i % (i + 1)
			existingIndices[i], existingIndices[j] = existingIndices[j], existingIndices[i]
