Greedily insert each ship into the existing assign that minimizes a weighted score combining cost increase and a proximity bonus based on Manhattan distance between stations, falling back to a new assign if no feasible insertion exists.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	const (
		costWeight     = 1.0
		proximityBonus = -5.0
		bigNumber      = 1e18
	)
	for jj := range oris {
		bestAssignIdx := -1
		bestScore := bigNumber
		shipID := total_ship + jj
		for ii := 0; ii < dispatch.AssignsLen; ii++ {
			savedCost := dispatch.Assigns[ii].Cost
			ok := dispatch.Assigns[ii].AddShip(shipID, oris[jj], dess[jj])
			if !ok {
				continue
			}
			dispatch.Assigns[ii].GenRoute()
			if dispatch.Assigns[ii].Cost < 0 {
				dispatch.Assigns[ii].RemoveShip(shipID)
				dispatch.Assigns[ii].GenRoute()
				continue
			}
			costIncrease := dispatch.Assigns[ii].Cost - savedCost
			score := costWeight*costIncrease +
				proximityBonus*(cal_dis(dispatch.Assigns[ii].StationCurrent, oris[jj])+
					cal_dis(oris[jj], dess[jj]))
			if score < bestScore {
				bestScore = score
				bestAssignIdx = ii
			}
			dispatch.Assigns[ii].RemoveShip(shipID)
			dispatch.Assigns[ii].GenRoute()
		}
		if bestAssignIdx != -1 {
			dispatch.Assigns[bestAssignIdx].AddShip(shipID, oris[jj], dess[jj])
			dispatch.Assigns[bestAssignIdx].GenRoute()
			continue
		}
		placed := false
		for ii := 0; ii < MAXASSIGNS; ii++ {
			if ii < dispatch.AssignsLen {
				continue
			}
			ok := dispatch.Assigns[ii].AddShip(shipID, oris[jj], dess[jj])
			if !ok {
				continue
			}
			dispatch.Assigns[ii].GenRoute()
			if dispatch.Assigns[ii].Cost >= 0 {
				if ii >= dispatch.AssignsLen {
					dispatch.AssignsLen = ii + 1
				}
				placed = true
				break
			} else {
				dispatch.Assigns[ii].RemoveShip(shipID)
				dispatch.Assigns[ii].GenRoute()
			}
		}
		if !placed {
			idx := dispatch.AssignsLen
			if idx < MAXASSIGNS {
