	for idx := range oris {
		bestAssignIdx := -1
		minDeltaCost := 1e308
		savedStates := make([]*Assign, dispatch.AssignsLen+1)
		oriId := total_ship + idx

		// Evaluate all existing non‑empty assigns plus one potential empty slot
		evalLimit := dispatch.AssignsLen
		if evalLimit == 0 || dispatch.Assigns[evalLimit-1].StationsLen == 0 {
			// Ensure we always have at least one target assign (the first empty one)
			evalLimit = 1
		}

		for i := 0; i < dispatch.AssignsLen; i++ {
			if dispatch.Assigns[i].StationsLen == 0 && i != dispatch.AssignsLen-1 {
				continue // Skip empty slots except possibly the last one used as buffer
			}
			// Save current state via deep copy of relevant fields
			savedStates[i] = &Assign{}
			*savedStates[i] = dispatch.Assigns[i]

			ok := dispatch.Assigns[i].AddShip(oriId, oris[idx], dess[idx])
			if ok {
				oldCost := savedStates[i].Cost
				dispatch.Assigns[i].GenRoute()
				delta := dispatch.Assigns[i].Cost - oldCost
				if delta >= 0 && delta < minDeltaCost {
					minDeltaCost = delta
					bestAssignIdx = i
				}
			}
			// Undo trial insertion
			dispatch.Assigns[i] = *savedStates[i]
			dispatch.Assigns[i].GenRoute()
		}

		// Also try a brand‑new assign (at index dispatch.AssignsLen if within MAXASSIGNS)
		newSlotIdx := -1
		if bestAssignIdx == -1 && dispatch.AssignsLen < MAXASSIGNS {
			i := dispatch.AssignsLen
			savedStates[i] = &Assign{} // placeholder
			// Create a clean assign implicitly by using a zero‑valued entry
			ok := dispatch.Assigns[i].AddShip(oriId, oris[idx], dess[idx])
			if ok {
				dispatch.Assigns[i].GenRoute()
				minDeltaCost = dispatch.Assigns[i].Cost
				bestAssignIdx = i
				newSlotIdx = i
			}
			if !ok {
				// Clean up the failed attempt
				dispatch.Assigns[i] = Assign{}
			}
		}

		// Apply the best insertion found
		if bestAssignIdx != -1 {
			if newSlotIdx == bestAssignIdx {
				// The new slot was already written during trial; just update length
				dispatch.AssignsLen++
			} else {
				// Re‑apply to the chosen existing assign
				dispatch.Assigns[bestAssignIdx].AddShip(oriId, oris[idx], dess[idx])
				dispatch.Assigns[bestAssignIdx].GenRoute()
			}
		} else {
			// Fallback: force insertion into a new assign regardless of feasibility flags;
			// this matches the requirement “never drop an order”.
			fallbackIdx := dispatch.AssignsLen
			if fallbackIdx < MAXASSIGNS {
				dispatch.Assigns[fallbackIdx].AddShip(oriId, oris[idx], dess[idx])
				dispatch.Assigns[fallbackIdx].GenRoute()
				dispatch.AssignsLen++
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch
}

